const fecha = new Date().toISOString().slice(0, 10).replace(/-/g, '');
const nombreArchivo = `bce_wti_${fecha}.json`;
const rutaArchivo = `/home/node/datos_macroentorno/bce/sector_externo/${nombreArchivo}`;

const contenido = JSON.stringify($input.all().map(item => item.json), null, 2);

return [
  {
    json: {
      nombre_archivo: nombreArchivo,
      ruta_archivo: rutaArchivo
    },
    binary: {
      data: {
        data: Buffer.from(contenido, 'utf8').toString('base64'),
        mimeType: 'application/json',
        fileName: nombreArchivo
      }
    }
  }
];

